    industry: 'technology',
    sub_vertical: 'cloud infrastructure',
    difficulty: 'advanced',
    estimated_minutes: 25,
    primary_competencies: ['strategy', 'market_analysis', 'systems_thinking'],
    secondary_competencies: ['stakeholder_management', 'prioritization'],
    frameworks: ['Market Sizing (TAM/SAM/SOM)', 'Build vs. Buy vs. Partner'],
